mapper.select:
SELECT point
FROM member
WHERE id = #{id}

mapper.update:
UPDATE
    member
SET
    point = point + #{amount}
WHERE
    id = #{id};

mapper.select:
SELECT m.point AS point, COALESCE(p.total_purchase_amount, 0) AS totalPurchaseAmount, COALESCE(s.total_sales_amount, 0) AS totalSalesAmount FROM member m
LEFT JOIN ( SELECT winner_id, SUM(winner_price) AS total_purchase_amount FROM winner_deal GROUP BY winner_id ) p ON m.id = p.winner_id
LEFT JOIN ( SELECT seller_id, SUM(winner_price) AS total_sales_amount FROM winner_deal GROUP BY seller_id ) s ON m.id = s.seller_id WHERE m.id = #{memberId}
